#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv1 = (vUv-0.5)*uAspect.xy;

float rad2 = length(uv1) + .05;
float rad1 = .1/rad2 ;

vec2 uv2 = vec2 (vAngle/3.14, rad1*1.5);
uv2.y = uv2.y  +0.1*uTime;
uv2.x = uv2.x  +.02*uTime;

vec2 uv3 = vec2 (vAngle/3.14, rad1);
uv3.y = uv3.y  + q30 ;
uv3.x = uv3.x  + uTime/32;


vec3 crisp = GetPixel(fract(uv2)) + 2*GetPixel(fract(uv3));
crisp += 2*GetBlur2(fract(uv2)) + 2*GetBlur2(fract(uv3));

vec3 lay1 = vec3 (1,0,1)*vUv.y*pow(1-vRadius,8);

crisp = 3*crisp * pow(vRadius,1);

float mask = clamp01(1-4*vRadius);

ret = crisp + lay1*mask + mask * GetPixel(fract(vUv));



vUv = (vUv-.5)* uAspect.xy + .5;
vec2 uvX = 1-vUv;

vec3 retX0 = texture(sampler_main,vUv) +2*GetBlur2 (vUv);
vec3 retX1 = texture(sampler_main,uvX) + 2*GetBlur2 (uvX);




vec3 retZ1 = retX0 + retX1  ;
vec3 retZ2 = retX0 * retX1  ;
vec3 retMIX1 = mix(retZ2, retZ1, q29 * .16);

ret = mix(ret,retMIX1,q29 * .5);

vec3 retI = 1 - ret;
//retI += .2;
//ret -= .2;
if(q29 > 0){
 zz = q29;
}
//ret =  mix(ret,retI,sin(uTime)*(zz));
//vec3 retN1 = mix(ret,retI,sin(uTime)*(zz));
ret =  mix(ret,retI,(q29*ret*(vRadius * (2-q29))));
//ret = mix(ret,retN1,sin(uTime));

ret *= ret + (audioHigh * .001);

  fragColor = ret;
}
